export function createPaymentModule(config) {
  return new PaymentModule(config);
}

export function usePaymentModule(config) {
  const moduleRef = useRef(null);
  if (!moduleRef.current) moduleRef.current = new PaymentModule(config);

  const [ready, setReady] = useState(false);
  const [iapReady, setIapReady] = useState(false);
  const [walletReady, setWalletReady] = useState(false);
  const [lastEvent, setLastEvent] = useState(null);

  useEffect(() => {
    const pm = moduleRef.current;
    let unsub = pm.onEvent((evt) => setLastEvent(evt));
    let mounted = true;
    (async () => {
      try {
        await pm.init();
        if (!mounted) return;
        setReady(true);
        setIapReady(!!pm.state.iapReady);
        setWalletReady(!!pm.state.walletReady);
      } catch (e) {
        if (!mounted) return;
        setReady(false);
      }
    })();
    return () => {
      mounted = false;
      try {
        unsub && unsub();
      } catch (e) {}
    };
  }, []);

  return useMemo(
    () => ({
      payment: moduleRef.current,
      ready,
      iapReady,
      walletReady,
      lastEvent,
    }),
    [ready, iapReady, walletReady, lastEvent]
  );
}

